public static long solve(long[] nums) {
    long count = 0;
    int n = nums.length;
    for (int i = 0; i < n; i++) {
        for (int j = i + 1; j < n; j++) {
            long a = nums[i];
            long b = nums[j];
            long absA = Math.abs(a);
            long absB = Math.abs(b);
            long minAbs = Math.min(absA, absB);
            long maxAbs = Math.max(absA, absB);

            long diff = Math.abs(a - b);
            long sum = Math.abs(a + b);
            long minDiffSum = Math.min(diff, sum);
            long maxDiffSum = Math.max(diff, sum);

            if (minDiffSum <= minAbs && maxDiffSum >= maxAbs) {
                count++;
            }
        }
    }
    return count;
}
