    int n = nums.length;
    for (int i = 0; i < n; i++) {
        for (int j = i + 1; j < n; j++) {
            long a = nums[i];
            long b = nums[j];
            long absDiff = Math.abs(a - b);
            long absSum = Math.abs(a + b);
            long minAbs = Math.min(Math.abs(a), Math.abs(b));
            long maxAbs = Math.max(Math.abs(a), Math.abs(b));

            long minCondition = Math.min(absDiff, absSum);
            long maxCondition = Math.max(absDiff, absSum);

            if (minCondition <= minAbs && maxCondition >= maxAbs) {
                count++;
            }
        }
    }
    return count;
}
